#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUvOriginal;
uv1 = (vUv-.2) * uAspect.xy;

//BACKGROUND
float z = 16*length(uv1)+uTime;
vec2 uvn =normalize(uv1);
rs = clamp(tan(z)*uvn,-5,5)/2;

//CRYSTAL
float mult = q31;
uv7 = sin(uv1*mult);
uv8 = uv7;
float dist = length(uv8);
dist *= (abs(uv1.x) + abs(uv1.y))+ q32;

float ang2 = atan(uv8.y,uv8.x);
ang2 =  .1*floor(16* ang2);
vec2 dir = .5*uv8+vec2 (cos(ang2), sin(ang2));


z = (1-cos(2*dist));
z = clamp01(z);

//ADD
float mask = (z >= .5); //momentan beliebig
rs = q28*rs + (1-q28)*rs.yx;
vUv += (1-mask)*.03*(rs.yx) + .5*mask*z*normalize(dir);

//ZENTRALSTRAHL
uv6 = multiply(uv1,mat2(_qb));
mus = abs(0.01/(sqrt(uv6.x)+.001))*(vRadius+.2);

//DOTS
vec2 uv2 = .7*uv1+.3*sin(uv1*16+4*vec2 (q5,q6));
uv2 *= .2;
vec3 dots = q26*clamp01(.001/(length(uv2)));
vec3 blur = GetBlur1(fract(vUv));
vec3 crisp= GetPixel(vUv);
vec3 diff = (crisp) - .5*blur;
vec3 ret1 = crisp + mus + dots;

vec3 mod = texture(sampler_noise_lq,.5*vUv+uTime*.01)-.2;
mod = 1 - mod*diff;

ret = (1-mask)*ret1*mod + mask*ret1*mod;
ret = ret *.75- .03;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = (vUv-0.5)*uAspect.xy;

//float ang1 = atan(uv1.y, uv1.x);
//float rad1 = log(length(uv1)-0.1);

float rad2 = length(uv1) + .2;
float rad1 = 0.15/rad2 ;

vec2 uv2 = vec2 (vAngle/3.14, rad1);
uv2.y = uv2.y  +0.15*uTime;
uv2.x = uv2.x  +.0*uTime;

vec2 uv3 = vec2 (vAngle/3.14, rad1*1.5);
uv3.y = uv3.y  +0.15*uTime ;
uv3.x = uv3.x  + uTime/32;

vec3 crisp = 2*GetPixel(uv2) + GetPixel(uv3);
crisp += 2*GetBlur2(fract(uv2)) + 2*GetBlur2(fract(uv3));

vec3 lay1 = vec3 (0,0,1)*vUv.y*pow(1-vRadius,8);

crisp = 3.5*crisp * pow(vRadius,1);

float mask = clamp01(1-200*vRadius);

ret = crisp + lay1*mask + mask * GetPixel(vUv);


  fragColor = ret;
}
